const API_URL = "http://127.0.0.1:3100";
const API_KEY = "eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.REDACTED.REDACTED";
const AGENT_ID = "c8f13871-13da-483b-bbcc-fe475a47bee3";
const COMPANY_ID = "fdff33dd-92aa-4b23-87f0-7f2d100d1665";
const TASK_ID = "af3f866f-be82-4b7d-901a-fe715f9cd8e1";

const headers = { "Authorization": `Bearer ${API_KEY}`, "Content-Type": "application/json" };

async function run() {
  // Get my identity
  const me = await fetch(`${API_URL}/api/agents/me`, { headers }).then(r => r.json());
  console.log("=== MY IDENTITY ===");
  console.log(`Role: ${me.role}, Name: ${me.name}, Budget: ${JSON.stringify(me.budget)}`);
  console.log(`Chain of command: ${JSON.stringify(me.chainOfCommand)}`);

  // Get the triggering task
  const task = await fetch(`${API_URL}/api/issues/${TASK_ID}`, { headers }).then(r => r.json());
  console.log("\n=== TRIGGERING TASK ===");
  console.log(`Identifier: ${task.identifier}`);
  console.log(`Title: ${task.title}`);
  console.log(`Status: ${task.status}`);
  console.log(`Priority: ${task.priority}`);
  console.log(`AssigneeAgentId: ${task.assigneeAgentId}`);
  console.log(`Description: ${task.description}`);
  if (task.ancestors) console.log(`Ancestors: ${JSON.stringify(task.ancestors.map(a => ({id: a.identifier, title: a.title})))}`);
  if (task.project) console.log(`Project: ${task.project.name}`);

  // Get comments
  const comments = await fetch(`${API_URL}/api/issues/${TASK_ID}/comments`, { headers }).then(r => r.json());
  const items = Array.isArray(comments) ? comments : (comments.items || []);
  console.log(`\n=== COMMENTS (${items.length}) ===`);
  for (const c of items) {
    console.log(`\n--- Comment ${c.id} ---`);
    console.log(`Author: ${c.authorAgentId || c.authorUserId || 'unknown'} | Created: ${c.createdAt}`);
    console.log(`Body: ${c.body}`);
  }

  // Get my assignments
  const assignments = await fetch(`${API_URL}/api/companies/${COMPANY_ID}/issues?assigneeAgentId=${AGENT_ID}&status=todo,in_progress,blocked`, { headers }).then(r => r.json());
  const aItems = Array.isArray(assignments) ? assignments : (assignments.items || []);
  console.log(`\n=== MY ASSIGNMENTS (${aItems.length}) ===`);
  for (const i of aItems) {
    console.log(`${i.identifier} | ${i.status} | ${i.priority} | ${i.title}`);
  }
}

run().catch(e => console.error(e));

