plugins {
	kotlin("jvm") version "2.2.21"
	kotlin("plugin.spring") version "2.2.21"
	id("org.springframework.boot") version "4.0.1"
	id("io.spring.dependency-management") version "1.1.7"
	id("org.graalvm.buildtools.native") version "0.11.3"
	id("com.google.cloud.tools.jib") version "3.5.2"
	id("build-cache-metrics")
}

// Configure build cache metrics reporting
buildCacheMetrics {
	enableLogging.set(false)          // Set to true to log individual cache hits/misses
	enableDetailedLogging.set(false)  // Set to true for debugging internal operations
	useInternalApi.set(true)          // Use internal API for local cache metrics
}

// OpenTelemetry Java Agent — auto-instruments WebFlux, WebClient, R2DBC, Netty
val otelAgent by configurations.creating

group = "com.keeplearning"
version = "0.0.1-SNAPSHOT"
description = "Authentication Backend"

java {
	toolchain {
		languageVersion = JavaLanguageVersion.of(21)
	}
}

repositories {
	mavenCentral()
}

dependencies {
	otelAgent("io.opentelemetry.javaagent:opentelemetry-javaagent:2.12.0")
	implementation("io.netty:netty-resolver-dns-native-macos:4.1.100.Final:osx-aarch_64")
	implementation("org.springframework.boot:spring-boot-starter-actuator")
	implementation("org.springframework.boot:spring-boot-starter-data-r2dbc")
	implementation("org.springframework.boot:spring-boot-starter-flyway")
	implementation("org.springframework.boot:spring-boot-starter-security")
	implementation("org.springframework.boot:spring-boot-starter-security-oauth2-client")
	implementation("org.springframework.boot:spring-boot-starter-oauth2-resource-server")
	implementation("org.springframework.boot:spring-boot-starter-webclient")
	implementation("org.springframework.boot:spring-boot-starter-webflux")
	implementation("io.projectreactor.kotlin:reactor-kotlin-extensions")
	implementation("org.flywaydb:flyway-database-postgresql")
	implementation("org.jetbrains.kotlin:kotlin-reflect")
	implementation("org.jetbrains.kotlinx:kotlinx-coroutines-core")
	implementation("org.jetbrains.kotlinx:kotlinx-coroutines-reactor")
	implementation("tools.jackson.module:jackson-module-kotlin")
	implementation("io.github.cdimascio:dotenv-kotlin:6.4.1")
	implementation("org.springdoc:springdoc-openapi-starter-webflux-ui:3.0.1")
	implementation("com.unboundid.product.scim2:scim2-sdk-common:4.0.0")
	implementation(project(":scim-common"))
	developmentOnly("org.springframework.boot:spring-boot-devtools")
	runtimeOnly("org.postgresql:postgresql")
	implementation("org.postgresql:r2dbc-postgresql")

	testImplementation("org.springframework.boot:spring-boot-starter-actuator-test")
	testImplementation("org.springframework.boot:spring-boot-starter-data-r2dbc-test")
	testImplementation("org.springframework.boot:spring-boot-starter-flyway-test")
	testImplementation("org.springframework.boot:spring-boot-starter-security-oauth2-client-test")
	testImplementation("org.springframework.boot:spring-boot-starter-security-test")
	testImplementation("org.springframework.boot:spring-boot-starter-webclient-test")
	testImplementation("org.springframework.boot:spring-boot-starter-webflux-test")
	testImplementation("org.jetbrains.kotlin:kotlin-test-junit5")
	testImplementation("org.jetbrains.kotlinx:kotlinx-coroutines-test")
	testImplementation("io.mockk:mockk:1.13.13")
	testRuntimeOnly("org.junit.platform:junit-platform-launcher")
	testRuntimeOnly("io.r2dbc:r2dbc-h2")
}

kotlin {
	compilerOptions {
		freeCompilerArgs.addAll("-Xjsr305=strict", "-Xannotation-default-target=param-property")
	}
}

tasks.withType<Test> {
	useJUnitPlatform()
	testLogging {
		events("passed", "skipped", "failed")
		showExceptions = true
		showCauses = true
		showStackTraces = true
		exceptionFormat = org.gradle.api.tasks.testing.logging.TestExceptionFormat.SHORT
	}
}

val copyOtelAgent by tasks.registering(Copy::class) {
	from(otelAgent)
	into(layout.buildDirectory.dir("otel"))
	rename { "opentelemetry-javaagent.jar" }
}

val jibTag: String? = findProperty("jibTag")?.toString()

jib {
	from {
		image = "eclipse-temurin:21-jre-noble"
		platforms {
			platform {
				architecture = "arm64"
				os = "linux"
			}
		}
	}
	to {
		image = "ghcr.io/dsjkeeplearning/kos-auth-backend:latest"
		tags = if (!jibTag.isNullOrBlank()) setOf(jibTag) else emptySet()
	}
	container {
		ports = listOf("8080")
		mainClass = "com.keeplearning.auth.KosAuthApplicationKt"
		creationTime.set("USE_CURRENT_TIMESTAMP")
		jvmFlags = listOf("-javaagent:/app/otel/opentelemetry-javaagent.jar")
	}
	extraDirectories {
		paths {
			path {
				setFrom(layout.buildDirectory.dir("otel"))
				into = "/app/otel"
			}
		}
	}
}

// Ensure OTel agent is copied before JIB builds the container
tasks.matching { it.name.startsWith("jib") }.configureEach {
	dependsOn(copyOtelAgent)
}

// Disable AOT processing for development (causes issues with R2DBC Json type)
tasks.named("processAot") {
	enabled = false
}

tasks.named("processTestAot") {
	enabled = false
}

plugins {
    // Using 1.8.2 instead of 1.9.5 for R2 compatibility
    // Newer versions use AWS SDK 2.40+ which adds checksum headers R2 doesn't support
    // See: https://community.cloudflare.REDACTED
    id("com.github.burrunan.s3-build-cache") version "1.8.2"
}

rootProject.name = "auth"

include("keycloak-spi")
include("scim-common")
include("forge")

// S3 Build Cache Configuration
// Set these environment variables in .env or shell:
//   S3_BUILD_CACHE_BUCKET - bucket name (required for remote cache)
//   S3_BUILD_CACHE_REGION - AWS region (use "auto" for R2, or "us-east-1")
//   S3_BUILD_CACHE_ENDPOINT - for S3-compatible storage (MinIO, R2, etc.)
//   AWS_ACCESS_KEY_ID or S3_BUILD_CACHE_ACCESS_KEY_ID - access key
//   AWS_SECRET_ACCESS_KEY or S3_BUILD_CACHE_SECRET_KEY - secret key
val s3Bucket: String? = System.getenv("S3_BUILD_CACHE_BUCKET")
val s3Region: String = System.getenv("S3_BUILD_CACHE_REGION") ?: "auto"
val s3Endpoint: String? = System.getenv("S3_BUILD_CACHE_ENDPOINT")
// Support both AWS standard names and custom S3_BUILD_CACHE_* names
val s3AccessKey: String? = System.getenv("AWS_ACCESS_KEY_ID")
    ?: System.getenv("S3_BUILD_CACHE_ACCESS_KEY_ID")
val s3SecretKey: String? = System.getenv("AWS_SECRET_ACCESS_KEY")
    ?: System.getenv("S3_BUILD_CACHE_SECRET_KEY")

buildCache {
    local {
        isEnabled = true
    }
    if (!s3Bucket.isNullOrBlank() && !s3AccessKey.isNullOrBlank() && !s3SecretKey.isNullOrBlank()) {
        remote<com.github.burrunan.s3cache.AwsS3BuildCache> {
            region = s3Region
            bucket = s3Bucket
            prefix = "gradle-cache/"
            isPush = true
            isEnabled = true
            awsAccessKeyId = s3AccessKey
            awsSecretKey = s3SecretKey
            isReducedRedundancy = false  // R2 doesn't support REDUCED_REDUNDANCY
            if (!s3Endpoint.isNullOrBlank()) {
                endpoint = s3Endpoint
                forcePathStyle = true  // Required for R2 and most S3-compatible storage
            }
        }
    }
}

